require"UI.UIBase"require"UI.UIBlock"require"UI.UI_Activity_Task"UI_Challenge_Task=UIBase:Inherit()UI_Challenge_Task.activity_id=1092;function UI_Challenge_Task:OnCreate()self.Inheritance=getmetatable(self)local a=ExcelMgr.GetData('activity','activity',UI_Challenge_Task.activity_id)['name_'..GameMgr.Inst.prefer_language]self.activity_name=string.gsub(a,'\\n','\n')self.btn_close.onClick:AddListener(function()self:Hide()end)end;function UI_Challenge_Task:Show()if self.locking then return end;self.locking=true;self.transform.gameObject:SetActive(true)self:AnimPopOut(self.transform,function()self.locking=false end)Tools.ImgOfLocalization('pic/myres/trial/banner',self.img_head,true)local b=UI_Activity.GetPeriodTaskList(UI_Challenge_Task.activity_id)self.Inheritance:RefreshView(b,'completePeriodActivityTask')end;function UI_Challenge_Task:Hide()if self.locking then return end;self.locking=true;self:AnimPopHide(self.transform,function()self.transform.gameObject:SetActive(false)self.locking=false end)end;function UI_Challenge_Task:need_popout()return true end;function UI_Challenge_Task:haveRedPoint()local b=UI_Activity.GetPeriodTaskList(UI_Activity.activity_level_id)for c=1,#b do if b[c].achieved and not b[c].rewarded then return true end end;return false end;return UI_Challenge_Task